import type { Metadata } from "next";
import InvoiceEditor from "./InvoiceEditor";

export const metadata: Metadata = {
  title: "請求書作成（インボイス対応） | ぐんじょう請求",
  description:
    "適格請求書（インボイス）に対応した請求書作成画面。取引先の選択、明細の追加・編集、税率別（10% / 8%軽減）の消費税内訳を自動計算し、プレビュー・下書き保存・発行ができます。",
};

export default function InvoicePage() {
  return <InvoiceEditor />;
}

/**
 * Domain types + tax math for the invoice editor.
 *
 * Tax handling follows 適格請求書 (qualified invoice) rules: consumption tax is
 * computed PER RATE on the per-rate 税抜 subtotal and rounded once per rate
 * (端数処理は税率ごとに1回), then summed — not rounded per line. We floor
 * (切り捨て), the most common JP invoice convention; a real product would make
 * this configurable.
 */

export type TaxRate = "10" | "8"; // 8 == 軽減税率 (reduced rate)

export interface LineItem {
  id: string;
  description: string;
  /** 数量 */
  quantity: number;
  /** 単価 (税抜, 円). Stored as a string so a cell can be cleared/retyped. */
  unitPrice: string;
  taxRate: TaxRate;
}

export interface Customer {
  id: string;
  name: string;
  /** 適格請求書発行事業者 登録番号 — T + 13 digits, optional on the customer side. */
  registrationNumber?: string;
}

export const TAX_RATE_OPTIONS: { value: TaxRate; label: string }[] = [
  { value: "10", label: "10%" },
  { value: "8", label: "8%（軽減）" },
];

export const HONORIFIC_OPTIONS = ["御中", "様"] as const;
export type Honorific = (typeof HONORIFIC_OPTIONS)[number];

export const CUSTOMER_MASTER: Customer[] = [
  { id: "c1", name: "株式会社あおぞら商事", registrationNumber: "T1234567890123" },
  { id: "c2", name: "みどりデザイン合同会社", registrationNumber: "T9876543210987" },
  { id: "c3", name: "白鳥フードサービス株式会社", registrationNumber: "T5555666677778" },
  { id: "c4", name: "個人事業主 山田太郎" },
];

let seq = 0;
export function newRowId(): string {
  seq += 1;
  return `row-${Date.now().toString(36)}-${seq}`;
}

export function createEmptyRow(taxRate: TaxRate = "10"): LineItem {
  return { id: newRowId(), description: "", quantity: 1, unitPrice: "", taxRate };
}

/** Parse a stored unit-price string to a non-negative integer yen amount. */
export function parseYen(value: string): number {
  const n = Number(value.replace(/[^\d]/g, ""));
  return Number.isFinite(n) ? n : 0;
}

/** 金額 = 数量 × 単価 (税抜). */
export function lineAmount(item: LineItem): number {
  return item.quantity * parseYen(item.unitPrice);
}

export interface RateBreakdown {
  rate: TaxRate;
  /** 税抜対象額 (この税率の小計) */
  net: number;
  /** 消費税額 (税率ごとに端数処理) */
  tax: number;
}

export interface Totals {
  /** 小計 (税抜合計) */
  subtotal: number;
  breakdown: RateBreakdown[];
  /** 消費税合計 */
  taxTotal: number;
  /** 合計金額 (税込) */
  grandTotal: number;
}

const RATE_FACTOR: Record<TaxRate, number> = { "10": 0.1, "8": 0.08 };

/**
 * Compute totals with per-rate rounding, per qualified-invoice rules.
 * Only rates that actually appear in the line items are reported.
 */
export function computeTotals(items: LineItem[]): Totals {
  const netByRate = new Map<TaxRate, number>();
  for (const item of items) {
    const amount = lineAmount(item);
    netByRate.set(item.taxRate, (netByRate.get(item.taxRate) ?? 0) + amount);
  }

  // Stable, predictable order: 10% before 8%.
  const order: TaxRate[] = ["10", "8"];
  const breakdown: RateBreakdown[] = order
    .filter((rate) => netByRate.has(rate))
    .map((rate) => {
      const net = netByRate.get(rate) ?? 0;
      const tax = Math.floor(net * RATE_FACTOR[rate]); // 端数切り捨て、税率ごと
      return { rate, net, tax };
    });

  const subtotal = breakdown.reduce((sum, b) => sum + b.net, 0);
  const taxTotal = breakdown.reduce((sum, b) => sum + b.tax, 0);
  return { subtotal, breakdown, taxTotal, grandTotal: subtotal + taxTotal };
}

export const SEED_ITEMS: LineItem[] = [
  { id: newRowId(), description: "Webサイト デザイン制作（トップページ）", quantity: 1, unitPrice: "180000", taxRate: "10" },
  { id: newRowId(), description: "下層ページ デザイン制作", quantity: 6, unitPrice: "35000", taxRate: "10" },
  { id: newRowId(), description: "コーディング作業（一式）", quantity: 1, unitPrice: "120000", taxRate: "10" },
  { id: newRowId(), description: "保守サポート 月額", quantity: 3, unitPrice: "20000", taxRate: "10" },
  { id: newRowId(), description: "打ち合わせ用 軽食・飲料（テイクアウト）", quantity: 1, unitPrice: "8000", taxRate: "8" },
];

"use client";

import * as React from "react";
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  Button,
  Input,
  Textarea,
  Combobox,
  DatePicker,
  Select,
  Statistic,
  Badge,
  Separator,
  Alert,
  AlertTitle,
  AlertDescription,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  DialogClose,
  Form,
  FormField,
  FormLabel,
  FormControl,
  FormMessage,
  FormDescription,
  formatCurrency,
  formatPercent,
} from "@gunjo/ui";
import {
  IconCheck,
  IconEye,
  IconDeviceFloppy,
  IconSend,
  IconPrinter,
  IconBuildingStore,
  IconAlertTriangle,
} from "@tabler/icons-react";
import {
  type LineItem,
  type Customer,
  type Honorific,
  CUSTOMER_MASTER,
  HONORIFIC_OPTIONS,
  SEED_ITEMS,
  TAX_RATE_OPTIONS,
  createEmptyRow,
  computeTotals,
  parseYen,
} from "./invoice-data";
import { LineItemsTable } from "./LineItemsTable";

const ISSUER = {
  name: "ぐんじょうクリエイティブ株式会社",
  registrationNumber: "T2010001234567",
  address: "〒150-0001 東京都渋谷区神宮前1-2-3 ぐんじょうビル5F",
  tel: "03-1234-5678",
  bank: "ぐんじょう銀行 渋谷支店 普通 1234567 グンジョウクリエイティブ（カ",
};

type SaveState = "idle" | "draft" | "issued";

function todayPlus(days: number): Date {
  const d = new Date();
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() + days);
  return d;
}

function formatDateJa(d: Date | undefined): string {
  if (!d) return "—";
  return `${d.getFullYear()}年${d.getMonth() + 1}月${d.getDate()}日`;
}

export default function InvoiceEditor() {
  // ---- Issuer / customer ----
  const [useNewCustomer, setUseNewCustomer] = React.useState(false);
  const [customerId, setCustomerId] = React.useState<string>("");
  const [newCustomerName, setNewCustomerName] = React.useState("");
  const [honorific, setHonorific] = React.useState<Honorific>("御中");

  // ---- Meta ----
  const [invoiceNo, setInvoiceNo] = React.useState("INV-2026-0042");
  const [subject, setSubject] = React.useState("Webサイト リニューアル制作費");
  const [issueDate, setIssueDate] = React.useState<Date | undefined>(todayPlus(0));
  const [dueDate, setDueDate] = React.useState<Date | undefined>(todayPlus(30));

  // ---- Line items ----
  const [items, setItems] = React.useState<LineItem[]>(SEED_ITEMS);

  // ---- Notes ----
  const [notes, setNotes] = React.useState(
    "お振込手数料は貴社負担にてお願いいたします。"
  );

  // ---- Flow state ----
  const [attempted, setAttempted] = React.useState(false);
  const [saveState, setSaveState] = React.useState<SaveState>("idle");
  const [previewOpen, setPreviewOpen] = React.useState(false);
  const [confirmOpen, setConfirmOpen] = React.useState(false);
  const liveRef = React.useRef<HTMLParagraphElement>(null);

  const selectedCustomer: Customer | undefined = React.useMemo(
    () => CUSTOMER_MASTER.find((c) => c.id === customerId),
    [customerId]
  );
  const resolvedCustomerName = useNewCustomer
    ? newCustomerName.trim()
    : selectedCustomer?.name ?? "";

  const totals = React.useMemo(() => computeTotals(items), [items]);

  // ---- Validation ----
  const invalidRowIds = React.useMemo(() => {
    const s = new Set<string>();
    for (const it of items) {
      if (it.quantity <= 0 || parseYen(it.unitPrice) <= 0) s.add(it.id);
    }
    return s;
  }, [items]);

  const customerError = !resolvedCustomerName ? "取引先を選択または入力してください" : undefined;
  const invoiceNoError = !invoiceNo.trim() ? "請求書番号を入力してください" : undefined;
  const itemsError =
    items.length === 0
      ? "明細を1件以上追加してください"
      : invalidRowIds.size > 0
      ? `数量・単価が未入力の明細が ${invalidRowIds.size} 件あります`
      : undefined;

  const errors = [customerError, invoiceNoError, itemsError].filter(Boolean) as string[];
  const isValid = errors.length === 0;

  // ---- Line item handlers ----
  const handleItemChange = React.useCallback((id: string, patch: Partial<LineItem>) => {
    setItems((prev) => prev.map((it) => (it.id === id ? { ...it, ...patch } : it)));
    setSaveState("idle");
  }, []);
  const handleRemove = React.useCallback((id: string) => {
    setItems((prev) => prev.filter((it) => it.id !== id));
    setSaveState("idle");
  }, []);
  const handleAdd = React.useCallback(() => {
    setItems((prev) => [...prev, createEmptyRow()]);
    setSaveState("idle");
  }, []);

  const announce = (msg: string) => {
    if (liveRef.current) liveRef.current.textContent = msg;
  };

  const handleSaveDraft = () => {
    setSaveState("draft");
    announce("下書きを保存しました。");
  };

  const handleIssueClick = () => {
    setAttempted(true);
    if (!isValid) {
      announce(`発行できません。${errors.join("、")}`);
      return;
    }
    setConfirmOpen(true);
  };

  const handleConfirmIssue = () => {
    setConfirmOpen(false);
    setSaveState("issued");
    announce(`請求書 ${invoiceNo} を発行しました。合計 ${formatCurrency(totals.grandTotal)}。`);
  };

  const isIssued = saveState === "issued";

  return (
    <main className="mx-auto w-full max-w-5xl px-4 py-8 sm:px-6 lg:px-8">
      {/* Polite live region for status announcements */}
      <p ref={liveRef} role="status" aria-live="polite" className="sr-only" />

      <header className="mb-6 flex flex-col gap-2 sm:flex-row sm:items-end sm:justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">請求書作成</h1>
          <p className="mt-1 text-sm text-muted-foreground">
            適格請求書（インボイス）対応。明細と税率を入力すると、税率別の消費税内訳を自動計算します。
          </p>
        </div>
        <Badge variant="info" className="w-fit">適格請求書発行事業者</Badge>
      </header>

      {isIssued && (
        <Alert variant="success" className="mb-6" role="status">
          <IconCheck className="h-4 w-4" aria-hidden />
          <AlertTitle>請求書を発行しました</AlertTitle>
          <AlertDescription>
            請求書番号 {invoiceNo} を {resolvedCustomerName} {honorific} 宛に発行しました。
            合計金額 {formatCurrency(totals.grandTotal)}。プレビューから印刷・PDF出力ができます。
          </AlertDescription>
        </Alert>
      )}

      {attempted && !isValid && (
        <Alert variant="destructive" className="mb-6" role="alert">
          <IconAlertTriangle className="h-4 w-4" aria-hidden />
          <AlertTitle>入力内容を確認してください</AlertTitle>
          <AlertDescription>
            <ul className="list-disc pl-5">
              {errors.map((e) => (
                <li key={e}>{e}</li>
              ))}
            </ul>
          </AlertDescription>
        </Alert>
      )}

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[1fr_320px]">
        {/* ===== Main column ===== */}
        <div className="flex flex-col gap-6">
          {/* --- 発行元 / 取引先 --- */}
          <Card>
            <CardHeader>
              <CardTitle as="h2">発行元・取引先</CardTitle>
              <CardDescription>登録番号付きの発行元と、請求先の取引先を指定します。</CardDescription>
            </CardHeader>
            <CardContent className="grid grid-cols-1 gap-6 md:grid-cols-2">
              {/* 発行元 */}
              <section aria-labelledby="issuer-heading" className="rounded-lg border bg-muted/30 p-4">
                <h3 id="issuer-heading" className="mb-2 flex items-center gap-2 text-sm font-semibold">
                  <IconBuildingStore className="h-4 w-4 text-muted-foreground" aria-hidden />
                  発行元
                </h3>
                <p className="text-sm font-medium">{ISSUER.name}</p>
                <dl className="mt-2 space-y-1 text-xs text-muted-foreground">
                  <div className="flex gap-2">
                    <dt className="shrink-0 font-medium text-foreground">登録番号</dt>
                    <dd className="tabular-nums">{ISSUER.registrationNumber}</dd>
                  </div>
                  <div className="flex gap-2">
                    <dt className="shrink-0 font-medium text-foreground">所在地</dt>
                    <dd>{ISSUER.address}</dd>
                  </div>
                  <div className="flex gap-2">
                    <dt className="shrink-0 font-medium text-foreground">TEL</dt>
                    <dd className="tabular-nums">{ISSUER.tel}</dd>
                  </div>
                </dl>
              </section>

              {/* 取引先 */}
              <section aria-labelledby="customer-heading">
                <h3 id="customer-heading" className="mb-2 text-sm font-semibold">取引先（請求先）</h3>
                <Form
                  onSubmit={(e) => e.preventDefault()}
                  className="gap-3"
                  aria-label="取引先の指定"
                >
                  {!useNewCustomer ? (
                    <FormField error={attempted ? customerError : undefined} required className="p-0">
                      <FormLabel>取引先を選択</FormLabel>
                      <FormControl>
                        <Combobox
                          options={CUSTOMER_MASTER.map((c) => ({ value: c.id, label: c.name }))}
                          value={customerId}
                          onValueChange={(v) => {
                            setCustomerId(v);
                            setSaveState("idle");
                          }}
                          placeholder="取引先マスタから選択…"
                          searchPlaceholder="取引先名で検索…"
                          emptyMessage="該当する取引先がありません"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormField>
                  ) : (
                    <FormField error={attempted ? customerError : undefined} required className="p-0">
                      <FormLabel>新規取引先 会社名</FormLabel>
                      <FormControl>
                        <Input
                          value={newCustomerName}
                          onChange={(e) => {
                            setNewCustomerName(e.target.value);
                            setSaveState("idle");
                          }}
                          placeholder="例）株式会社サンプル"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormField>
                  )}

                  <div className="px-0">
                    <Button
                      type="button"
                      variant="link"
                      size="sm"
                      className="h-auto p-0"
                      onClick={() => {
                        setUseNewCustomer((v) => !v);
                        setSaveState("idle");
                      }}
                    >
                      {useNewCustomer ? "取引先マスタから選択する" : "+ 新規取引先を入力する"}
                    </Button>
                  </div>

                  <FormField className="p-0">
                    <FormLabel htmlFor="honorific">敬称</FormLabel>
                    <FormControl>
                      <Select
                        id="honorific"
                        value={honorific}
                        onChange={(e) => setHonorific(e.target.value as Honorific)}
                      >
                        {HONORIFIC_OPTIONS.map((h) => (
                          <option key={h} value={h}>
                            {h}
                          </option>
                        ))}
                      </Select>
                    </FormControl>
                  </FormField>

                  {!useNewCustomer && selectedCustomer?.registrationNumber && (
                    <p className="text-xs text-muted-foreground">
                      取引先登録番号：<span className="tabular-nums">{selectedCustomer.registrationNumber}</span>
                    </p>
                  )}
                </Form>
              </section>
            </CardContent>
          </Card>

          {/* --- 請求書メタ --- */}
          <Card>
            <CardHeader>
              <CardTitle as="h2">請求書情報</CardTitle>
            </CardHeader>
            <CardContent>
              <Form onSubmit={(e) => e.preventDefault()} className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                <FormField error={attempted ? invoiceNoError : undefined} required className="p-0">
                  <FormLabel>請求書番号</FormLabel>
                  <FormControl>
                    <Input
                      value={invoiceNo}
                      onChange={(e) => {
                        setInvoiceNo(e.target.value);
                        setSaveState("idle");
                      }}
                      placeholder="INV-0000"
                    />
                  </FormControl>
                  <FormMessage />
                </FormField>

                <FormField className="p-0">
                  <FormLabel>件名</FormLabel>
                  <FormControl>
                    <Input
                      value={subject}
                      onChange={(e) => setSubject(e.target.value)}
                      placeholder="請求の件名"
                    />
                  </FormControl>
                </FormField>

                <FormField className="p-0">
                  <FormLabel htmlFor="issue-date">発行日</FormLabel>
                  <FormControl>
                    <DatePicker id="issue-date" value={issueDate} onValueChange={setIssueDate} />
                  </FormControl>
                </FormField>

                <FormField className="p-0">
                  <FormLabel htmlFor="due-date">支払期日</FormLabel>
                  <FormControl>
                    <DatePicker id="due-date" value={dueDate} onValueChange={setDueDate} />
                  </FormControl>
                  <FormDescription>請求書の支払い期限です。</FormDescription>
                </FormField>
              </Form>
            </CardContent>
          </Card>

          {/* --- 明細 --- */}
          <Card>
            <CardHeader>
              <CardTitle as="h2">明細</CardTitle>
              <CardDescription>
                品目・数量・単価・税率を入力すると、金額（税抜）が自動計算されます。軽減税率（8%）の対象品目は税率欄で切り替えてください。
              </CardDescription>
            </CardHeader>
            <CardContent>
              <LineItemsTable
                items={items}
                onChange={handleItemChange}
                onRemove={handleRemove}
                onAdd={handleAdd}
                invalidRowIds={attempted ? invalidRowIds : new Set()}
              />
            </CardContent>
          </Card>

          {/* --- 備考 / 振込先 --- */}
          <Card>
            <CardHeader>
              <CardTitle as="h2">備考・振込先</CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
              <div className="rounded-lg border bg-muted/30 p-4">
                <h3 className="mb-1 text-sm font-semibold">お振込先</h3>
                <p className="text-sm tabular-nums">{ISSUER.bank}</p>
              </div>
              <Form onSubmit={(e) => e.preventDefault()}>
                <FormField className="p-0">
                  <FormLabel>備考</FormLabel>
                  <FormControl>
                    <Textarea
                      value={notes}
                      onChange={(e) => setNotes(e.target.value)}
                      rows={3}
                      placeholder="特記事項があれば入力してください"
                    />
                  </FormControl>
                </FormField>
              </Form>
            </CardContent>
          </Card>
        </div>

        {/* ===== Summary sidebar (sticky on desktop) ===== */}
        <aside className="lg:sticky lg:top-6 lg:self-start">
          <Card aria-labelledby="summary-heading">
            <CardHeader>
              <CardTitle as="h2" id="summary-heading">金額サマリー</CardTitle>
              <CardDescription>明細の変更に応じて自動で再計算されます。</CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
              <Statistic label="小計（税抜）" value={formatCurrency(totals.subtotal)} />

              <Separator />

              {/* 税率別内訳 — required for qualified invoices */}
              <div>
                <h3 className="mb-2 text-xs font-semibold text-muted-foreground">税率別内訳</h3>
                {totals.breakdown.length === 0 ? (
                  <p className="text-sm text-muted-foreground">明細を入力すると表示されます。</p>
                ) : (
                  <dl className="space-y-2 text-sm">
                    {totals.breakdown.map((b) => {
                      const rateLabel =
                        TAX_RATE_OPTIONS.find((o) => o.value === b.rate)?.label ?? `${b.rate}%`;
                      return (
                        <div key={b.rate} className="rounded-md border bg-muted/20 p-2.5">
                          <div className="flex items-center justify-between">
                            <dt className="font-medium">{rateLabel} 対象</dt>
                            <dd className="tabular-nums">{formatCurrency(b.net)}</dd>
                          </div>
                          <div className="mt-1 flex items-center justify-between text-xs text-muted-foreground">
                            <dt>
                              消費税（{formatPercent(b.rate === "10" ? 0.1 : 0.08)}）
                            </dt>
                            <dd className="tabular-nums">{formatCurrency(b.tax)}</dd>
                          </div>
                        </div>
                      );
                    })}
                  </dl>
                )}
              </div>

              <Separator />

              <div className="flex items-center justify-between text-sm">
                <span className="text-muted-foreground">消費税合計</span>
                <span className="font-medium tabular-nums">{formatCurrency(totals.taxTotal)}</span>
              </div>

              <div className="rounded-lg bg-primary-subtle p-3">
                <Statistic
                  label="合計金額（税込）"
                  value={formatCurrency(totals.grandTotal)}
                />
              </div>

              <Separator />

              <div className="flex flex-col gap-2">
                <Button type="button" variant="outline" onClick={() => setPreviewOpen(true)}>
                  <IconEye className="mr-1.5 h-4 w-4" aria-hidden />
                  プレビュー
                </Button>
                <Button type="button" variant="secondary" onClick={handleSaveDraft}>
                  <IconDeviceFloppy className="mr-1.5 h-4 w-4" aria-hidden />
                  {saveState === "draft" ? "下書きを保存しました" : "下書き保存"}
                </Button>
                <Button type="button" variant="primary" onClick={handleIssueClick} disabled={isIssued}>
                  <IconSend className="mr-1.5 h-4 w-4" aria-hidden />
                  {isIssued ? "発行済み" : "発行する"}
                </Button>
              </div>
            </CardContent>
          </Card>
        </aside>
      </div>

      {/* ===== Preview dialog ===== */}
      <Dialog open={previewOpen} onOpenChange={setPreviewOpen}>
        <DialogContent className="max-h-[90vh] max-w-2xl overflow-y-auto">
          <DialogHeader>
            <DialogTitle>請求書プレビュー</DialogTitle>
            <DialogDescription>発行前の内容を確認できます。</DialogDescription>
          </DialogHeader>
          <InvoicePreview
            issuer={ISSUER}
            customerName={resolvedCustomerName || "（取引先未選択）"}
            honorific={honorific}
            invoiceNo={invoiceNo}
            subject={subject}
            issueDate={issueDate}
            dueDate={dueDate}
            items={items}
            totals={totals}
            notes={notes}
          />
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => window.print()}>
              <IconPrinter className="mr-1.5 h-4 w-4" aria-hidden />
              印刷 / PDF
            </Button>
            <DialogClose asChild>
              <Button type="button" variant="secondary">閉じる</Button>
            </DialogClose>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* ===== Issue confirm dialog ===== */}
      <Dialog open={confirmOpen} onOpenChange={setConfirmOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>この内容で請求書を発行しますか？</DialogTitle>
            <DialogDescription>
              発行後は取引先に送付できる状態になります。内容に誤りがないかご確認ください。
            </DialogDescription>
          </DialogHeader>
          <dl className="space-y-2 rounded-lg border bg-muted/30 p-4 text-sm">
            <div className="flex justify-between gap-4">
              <dt className="text-muted-foreground">取引先</dt>
              <dd className="text-right font-medium">{resolvedCustomerName} {honorific}</dd>
            </div>
            <div className="flex justify-between gap-4">
              <dt className="text-muted-foreground">請求書番号</dt>
              <dd className="text-right tabular-nums">{invoiceNo}</dd>
            </div>
            <div className="flex justify-between gap-4">
              <dt className="text-muted-foreground">合計金額</dt>
              <dd className="text-right text-base font-bold tabular-nums">
                {formatCurrency(totals.grandTotal)}
              </dd>
            </div>
          </dl>
          <DialogFooter>
            <DialogClose asChild>
              <Button type="button" variant="outline">キャンセル</Button>
            </DialogClose>
            <Button type="button" variant="primary" onClick={handleConfirmIssue}>
              <IconSend className="mr-1.5 h-4 w-4" aria-hidden />
              発行する
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}

