"use client";

import * as React from "react";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
  Button,
  Input,
  NumberInput,
  Select,
  EmptyState,
  formatCurrency,
} from "@gunjo/ui";
import { IconTrash, IconPlus, IconListDetails } from "@tabler/icons-react";
import {
  type LineItem,
  type TaxRate,
  TAX_RATE_OPTIONS,
  lineAmount,
  parseYen,
} from "./invoice-data";

export interface LineItemsTableProps {
  items: LineItem[];
  onChange: (id: string, patch: Partial<LineItem>) => void;
  onRemove: (id: string) => void;
  onAdd: () => void;
  /** ids of rows flagged invalid (e.g. qty 0 / 単価 missing), for inline error styling. */
  invalidRowIds: Set<string>;
}

const cellInputClass =
  "h-9 text-sm";

function rowError(item: LineItem): string | null {
  if (item.quantity <= 0) return "数量は1以上で入力してください";
  if (parseYen(item.unitPrice) <= 0) return "単価を入力してください";
  return null;
}

/**
 * Hand-rolled editable line-item grid — @gunjo/ui has no editable table /
 * data-grid primitive (Table is static; DataTable is read-only). Desktop = a
 * real <table> with per-cell controls; mobile (<640px) = a stacked card list so
 * we don't shrink a 6-column editable table into oblivion.
 */
export function LineItemsTable({
  items,
  onChange,
  onRemove,
  onAdd,
  invalidRowIds,
}: LineItemsTableProps) {
  if (items.length === 0) {
    return (
      <div className="rounded-lg border border-dashed">
        <EmptyState
          icon={<IconListDetails aria-hidden />}
          title="明細がありません"
          description="「明細を追加」を押して、品目・数量・単価を入力してください。"
          action={
            <Button type="button" variant="primary" onClick={onAdd}>
              <IconPlus className="mr-1.5 h-4 w-4" aria-hidden />
              明細を追加
            </Button>
          }
        />
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-3">
      {/* ---- Desktop: editable table ---- */}
      <div className="hidden sm:block">
        <Table>
          <caption className="sr-only">
            請求明細。各行の品目・数量・単価・税率を編集でき、金額は自動計算されます。
          </caption>
          <TableHeader>
            <TableRow>
              <TableHead scope="col" className="w-[36%]">品目</TableHead>
              <TableHead scope="col" className="w-[10%] text-right">数量</TableHead>
              <TableHead scope="col" className="w-[18%] text-right">単価（円・税抜）</TableHead>
              <TableHead scope="col" className="w-[14%]">税率</TableHead>
              <TableHead scope="col" className="w-[16%] text-right">金額（税抜）</TableHead>
              <TableHead scope="col" className="w-[6%] text-center">
                <span className="sr-only">操作</span>
              </TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {items.map((item, index) => {
              const n = index + 1;
              const err = rowError(item);
              const isInvalid = invalidRowIds.has(item.id) && Boolean(err);
              return (
                <TableRow key={item.id} className={isInvalid ? "bg-destructive-subtle/40" : undefined}>
                  <TableCell>
                    <Input
                      aria-label={`${n}行目 品目`}
                      value={item.description}
                      onChange={(e) => onChange(item.id, { description: e.target.value })}
                      placeholder="品目・摘要"
                      className={cellInputClass}
                    />
                  </TableCell>
                  <TableCell className="text-right">
                    <NumberInput
                      aria-label={`${n}行目 数量`}
                      value={item.quantity}
                      onValueChange={(v) => onChange(item.id, { quantity: v })}
                      min={0}
                      step={1}
                      aria-invalid={isInvalid && item.quantity <= 0 ? true : undefined}
                      className="ml-auto w-24"
                    />
                  </TableCell>
                  <TableCell className="text-right">
                    <Input
                      aria-label={`${n}行目 単価`}
                      inputMode="numeric"
                      value={item.unitPrice}
                      onChange={(e) =>
                        onChange(item.id, { unitPrice: e.target.value.replace(/[^\d]/g, "") })
                      }
                      placeholder="0"
                      aria-invalid={isInvalid && parseYen(item.unitPrice) <= 0 ? true : undefined}
                      className={`${cellInputClass} text-right tabular-nums`}
                    />
                  </TableCell>
                  <TableCell>
                    <Select
                      aria-label={`${n}行目 税率`}
                      value={item.taxRate}
                      onChange={(e) => onChange(item.id, { taxRate: e.target.value as TaxRate })}
                    >
                      {TAX_RATE_OPTIONS.map((opt) => (
                        <option key={opt.value} value={opt.value}>
                          {opt.label}
                        </option>
                      ))}
                    </Select>
                  </TableCell>
                  <TableCell className="text-right align-middle font-medium tabular-nums">
                    {formatCurrency(lineAmount(item))}
                  </TableCell>
                  <TableCell className="text-center">
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      onClick={() => onRemove(item.id)}
                      aria-label={`${n}行目を削除`}
                      className="text-muted-foreground hover:text-destructive"
                    >
                      <IconTrash className="h-4 w-4" aria-hidden />
                    </Button>
                  </TableCell>
                </TableRow>
              );
            })}
          </TableBody>
        </Table>
        {/* Per-row validation messages, announced (under the table, associated by row number). */}
        {items.some((it) => invalidRowIds.has(it.id) && rowError(it)) && (
          <ul className="mt-2 space-y-1" aria-live="polite">
            {items.map((it, i) => {
              const err = rowError(it);
              if (!invalidRowIds.has(it.id) || !err) return null;
              return (
                <li key={it.id} className="text-xs font-medium text-destructive" role="alert">
                  {i + 1}行目：{err}
                </li>
              );
            })}
          </ul>
        )}
      </div>

      {/* ---- Mobile: stacked editable cards ---- */}
      <ul className="flex flex-col gap-3 sm:hidden">
        {items.map((item, index) => {
          const n = index + 1;
          const err = rowError(item);
          const isInvalid = invalidRowIds.has(item.id) && Boolean(err);
          return (
            <li
              key={item.id}
              className={`rounded-lg border bg-card p-4 ${isInvalid ? "border-destructive-border" : ""}`}
            >
              <div className="mb-2 flex items-center justify-between">
                <span className="text-xs font-semibold text-muted-foreground">明細 {n}</span>
                <Button
                  type="button"
                  variant="ghost"
                  size="icon"
                  onClick={() => onRemove(item.id)}
                  aria-label={`${n}行目を削除`}
                  className="h-8 w-8 text-muted-foreground hover:text-destructive"
                >
                  <IconTrash className="h-4 w-4" aria-hidden />
                </Button>
              </div>
              <div className="flex flex-col gap-3">
                <label className="flex flex-col gap-1 text-xs font-medium">
                  品目
                  <Input
                    aria-label={`${n}行目 品目`}
                    value={item.description}
                    onChange={(e) => onChange(item.id, { description: e.target.value })}
                    placeholder="品目・摘要"
                  />
                </label>
                <div className="grid grid-cols-2 gap-3">
                  <label className="flex flex-col gap-1 text-xs font-medium">
                    数量
                    <NumberInput
                      aria-label={`${n}行目 数量`}
                      value={item.quantity}
                      onValueChange={(v) => onChange(item.id, { quantity: v })}
                      min={0}
                      step={1}
                      layout="stepper"
                      aria-invalid={isInvalid && item.quantity <= 0 ? true : undefined}
                    />
                  </label>
                  <label className="flex flex-col gap-1 text-xs font-medium">
                    税率
                    <Select
                      aria-label={`${n}行目 税率`}
                      value={item.taxRate}
                      onChange={(e) => onChange(item.id, { taxRate: e.target.value as TaxRate })}
                    >
                      {TAX_RATE_OPTIONS.map((opt) => (
                        <option key={opt.value} value={opt.value}>
                          {opt.label}
                        </option>
                      ))}
                    </Select>
                  </label>
                </div>
                <label className="flex flex-col gap-1 text-xs font-medium">
                  単価（円・税抜）
                  <Input
                    aria-label={`${n}行目 単価`}
                    inputMode="numeric"
                    value={item.unitPrice}
                    onChange={(e) =>
                      onChange(item.id, { unitPrice: e.target.value.replace(/[^\d]/g, "") })
                    }
                    placeholder="0"
                    aria-invalid={isInvalid && parseYen(item.unitPrice) <= 0 ? true : undefined}
                    className="text-right tabular-nums"
                  />
                </label>
                <div className="flex items-center justify-between border-t pt-2 text-sm">
                  <span className="text-muted-foreground">金額（税抜）</span>
                  <span className="font-semibold tabular-nums">{formatCurrency(lineAmount(item))}</span>
                </div>
                {isInvalid && err && (
                  <p className="text-xs font-medium text-destructive" role="alert">
                    {err}
                  </p>
                )}
              </div>
            </li>
          );
        })}
      </ul>

      <div>
        <Button type="button" variant="outline" onClick={onAdd} className="w-full sm:w-auto">
          <IconPlus className="mr-1.5 h-4 w-4" aria-hidden />
          明細を追加
        </Button>
      </div>
    </div>
  );
}
